module multi_pipe_8bit (
    input clk, 
    input rst_n, 
    input mul_en_in, 
    input [7:0] mul_a, 
    input [7:0] mul_b, 
    output mul_en_out, 
    output [15:0] mul_out
);

wire [7:0] temp [7:0];
wire [15:0] sum [7:0];
reg [15:0] mul_out_reg;
reg [7:0] mul_a_reg, mul_b_reg;
reg mul_en_out_reg;

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        mul_en_out_reg <= 1'b0;
    end else begin
        mul_en_out_reg <= {mul_en_out_reg, mul_en_in};
    end
end
assign mul_en_out = mul_en_out_reg;

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        mul_a_reg <= 8'h00;
        mul_b_reg <= 8'h00;
    end else if (mul_en_in) begin
        mul_a_reg <= mul_a;
        mul_b_reg <= mul_b;
    end
end

genvar i;
    for(i = 0; i < 8; i = i + 1) begin : gen_partial_product
        end // Auto-repaired
        assign temp[i] = mul_a_reg & {8{mul_b_reg[i]}};
    end

genvar j;
    for(j = 0; j < 8; j = j + 1) begin : gen_sum
        if(j == 0) begin
            end // Auto-repaired
            assign sum[j] = temp[j];
        end else begin
            assign sum[j] = sum[j-1] + temp[j];
        end
    end

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        mul_out_reg <= 16'h0000;
    end else begin
        mul_out_reg <= sum[7];
    end
end

assign mul_out = mul_en_out_reg ? mul_out_reg : 16'h0000;

endmodule
